/** @module sso-provider-table */

import {
  getComponentStyles,
  type IdentityProvider,
  STRATEGY_DISPLAY_NAMES,
  MY_ORGANIZATION_SSO_PROVIDER_TABLE_SCOPES,
} from '@auth0/universal-components-core';
import { Plus } from 'lucide-react';
import * as React from 'react';

import { SsoProviderDeleteModal } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-delete/provider-delete-modal';
import { SsoProviderRemoveFromOrganizationModal } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-remove/provider-remove-modal';
import { SsoProviderTableActionsColumn } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-table/sso-provider-table-action';
import { DataTable, type Column } from '@/components/auth0/shared/data-table';
import { Header } from '@/components/auth0/shared/header';
import { withMyOrganizationService } from '@/hoc/with-services';
import { useConfig } from '@/hooks/my-organization/use-config';
import { useIdpConfig } from '@/hooks/my-organization/use-idp-config';
import { useSsoProviderTable } from '@/hooks/my-organization/use-sso-provider-table';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import type { SsoProviderTableProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-table-types';

/**
 * Internal SSO provider table component.
 * @param props - Component props
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.styling - Custom styling configuration with variables and classes
 * @param props.readOnly - Whether the component is in read-only mode
 * @param props.createAction - Configuration for the create action
 * @param props.editAction - Configuration for the edit action
 * @param props.deleteAction - Configuration for the delete action
 * @param props.deleteFromOrganizationAction - Configuration for removing from organization
 * @param props.enableProviderAction - Configuration for enabling a provider
 * @returns JSX element
 * @internal
 */
function SsoProviderTableComponent({
  customMessages = {},
  styling = {
    variables: { common: {}, light: {}, dark: {} },
    classes: {},
  },
  readOnly = false,
  createAction,
  editAction,
  deleteAction,
  deleteFromOrganizationAction,
  enableProviderAction,
}: SsoProviderTableProps) {
  const { isDarkMode } = useTheme();
  const { t } = useTranslator('idp_management.sso_provider_table', customMessages);

  const {
    providers,
    isLoading,
    isDeleting,
    isRemoving,
    isUpdating,
    isUpdatingId,
    onDeleteConfirm,
    onRemoveConfirm,
    onEnableProvider,
    organization,
  } = useSsoProviderTable(
    deleteAction,
    deleteFromOrganizationAction,
    enableProviderAction,
    customMessages,
  );
  const { isLoadingConfig, shouldAllowDeletion, isConfigValid } = useConfig();
  const { isLoadingIdpConfig, isIdpConfigValid } = useIdpConfig();

  const shouldHideCreate = !isConfigValid || !isIdpConfigValid;
  const isViewLoading = isLoading || isLoadingConfig || isLoadingIdpConfig;

  const [showDeleteModal, setShowDeleteModal] = React.useState(false);
  const [showRemoveModal, setShowRemoveModal] = React.useState(false);
  const [selectedIdp, setSelectedIdp] = React.useState<IdentityProvider | null>(null);

  const currentStyles = React.useMemo(
    () => getComponentStyles(styling, isDarkMode),
    [styling, isDarkMode],
  );

  const handleCreate = React.useCallback(() => {
    if (createAction?.onAfter) {
      createAction.onAfter();
    }
  }, [createAction]);

  const handleEdit = React.useCallback(
    (idp: IdentityProvider) => {
      if (editAction?.onAfter) {
        editAction.onAfter(idp);
      }
    },
    [editAction],
  );

  const handleDelete = React.useCallback(
    (idp: IdentityProvider) => {
      setSelectedIdp(idp);

      if (deleteAction?.onBefore) {
        const shouldProceed = deleteAction.onBefore(idp);
        if (!shouldProceed) return;
      }

      setShowDeleteModal(true);
    },
    [deleteAction],
  );

  const handleDeleteFromOrganization = React.useCallback(
    (idp: IdentityProvider) => {
      setSelectedIdp(idp);

      if (deleteFromOrganizationAction?.onBefore) {
        const shouldProceed = deleteFromOrganizationAction.onBefore(idp);
        if (!shouldProceed) return;
      }

      setShowRemoveModal(true);
    },
    [deleteFromOrganizationAction],
  );

  const handleToggleEnabled = React.useCallback(
    async (idp: IdentityProvider, enabled: boolean) => {
      if (readOnly || !onEnableProvider) return;

      await onEnableProvider(idp, enabled);
    },
    [readOnly, onEnableProvider],
  );

  const handleDeleteConfirm = React.useCallback(
    async (provider: IdentityProvider) => {
      await onDeleteConfirm(provider);
      setShowDeleteModal(false);
      setSelectedIdp(null);
    },
    [onDeleteConfirm, selectedIdp],
  );

  const handleRemoveConfirm = React.useCallback(
    async (provider: IdentityProvider) => {
      await onRemoveConfirm(provider);
      setShowRemoveModal(false);
      setSelectedIdp(null);
    },
    [onRemoveConfirm],
  );

  const columns: Column<IdentityProvider>[] = React.useMemo(
    () => [
      {
        type: 'text',
        accessorKey: 'name',
        title: t('table.columns.name'),
        width: '25%',
        render: (idp) => <div className="font-medium text-muted-foreground">{idp.name}</div>,
      },
      {
        type: 'text',
        accessorKey: 'display_name',
        width: '30%',
        title: t('table.columns.display_name'),
        render: (idp) => <div className="text-muted-foreground">{idp.display_name}</div>,
      },
      {
        type: 'text',
        accessorKey: 'strategy',
        title: t('table.columns.identity_provider'),
        width: '25%',
        render: (idp) => (
          <div className="text-muted-foreground">{STRATEGY_DISPLAY_NAMES[idp.strategy]}</div>
        ),
      },
      {
        type: 'actions',
        title: '',
        width: '20%',
        render: (idp) => (
          <SsoProviderTableActionsColumn
            provider={idp}
            shouldAllowDeletion={shouldAllowDeletion}
            readOnly={readOnly}
            isUpdating={isUpdating}
            isUpdatingId={isUpdatingId}
            customMessages={customMessages}
            edit={editAction}
            onToggleEnabled={handleToggleEnabled}
            onEdit={handleEdit}
            onDelete={handleDelete}
            onRemoveFromOrganization={handleDeleteFromOrganization}
          />
        ),
      },
    ],
    [
      t,
      readOnly,
      editAction,
      isUpdating,
      handleEdit,
      handleDelete,
      handleDeleteFromOrganization,
      handleToggleEnabled,
    ],
  );

  return (
    <div style={currentStyles.variables}>
      <div className={currentStyles.classes?.['SsoProviderTable-header']}>
        <Header
          title={t('header.title')}
          description={t('header.description')}
          actions={[
            {
              type: 'button',
              label: t('header.create_button_text'),
              onClick: () => handleCreate(),
              icon: Plus,
              hidden: shouldHideCreate || isViewLoading,
              disabled: createAction?.disabled || readOnly,
            },
          ]}
        />
      </div>

      <DataTable
        loading={isViewLoading}
        columns={columns}
        data={providers}
        emptyState={{ title: t('table.empty_message') }}
        className={currentStyles.classes?.['SsoProviderTable-table']}
      />

      {selectedIdp && (
        <SsoProviderDeleteModal
          className={currentStyles.classes?.['SsoProviderTable-deleteProviderModal']}
          isOpen={showDeleteModal}
          onClose={() => setShowDeleteModal(false)}
          provider={selectedIdp}
          onDelete={handleDeleteConfirm}
          isLoading={isDeleting}
          customMessages={customMessages.delete_modal}
        />
      )}

      {selectedIdp && (
        <SsoProviderRemoveFromOrganizationModal
          className={
            currentStyles.classes?.['SsoProviderTable-deleteProviderFromOrganizationModal']
          }
          isOpen={showRemoveModal}
          onClose={() => setShowRemoveModal(false)}
          provider={selectedIdp}
          organizationName={organization?.name}
          onRemove={handleRemoveConfirm}
          isLoading={isRemoving}
          customMessages={customMessages.remove_modal}
        />
      )}
    </div>
  );
}

/**
 * SSO identity providers table.
 *
 * Displays a table of SSO identity providers with actions for creating, editing,
 * enabling/disabling, deleting, and removing providers from the organization.
 *
 * @param props - {@link SsoProviderTableProps}
 * @param props.customMessages - Custom i18n message overrides
 * @param props.styling - CSS variables and class overrides
 * @param props.readOnly - Render in read-only mode
 * @param props.createAction - Lifecycle hooks for provider creation
 * @param props.editAction - Lifecycle hooks for provider editing
 * @param props.deleteAction - Lifecycle hooks for provider deletion
 * @param props.deleteFromOrganizationAction - Lifecycle hooks for removing provider from organization
 * @param props.enableProviderAction - Lifecycle hooks for enabling/disabling provider
 * @returns SSO provider table component
 *
 * @see {@link SsoProviderTableProps} for full props documentation
 *
 * @example
 * ```tsx
 * <SsoProviderTable
 *   createAction={{ onAfter: () => navigate('/providers/new') }}
 *   editAction={{ onAfter: (provider) => navigate(`/providers/${provider.id}`) }}
 *   deleteAction={{
 *     onBefore: (provider) => confirm(`Delete ${provider.name}?`),
 *     onAfter: (provider) => console.log('Deleted:', provider),
 *   }}
 * />
 * ```
 */
export const SsoProviderTable: React.ComponentType<SsoProviderTableProps> =
  withMyOrganizationService(SsoProviderTableComponent, MY_ORGANIZATION_SSO_PROVIDER_TABLE_SCOPES);

/**
 * SSO provider deletion modal content.
 * @module provider-delete-modal-content
 * @internal
 */

import React from 'react';

import { Label } from '@/components/ui/label';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { SsoProviderDeleteModalContentProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-delete-types';

/**
 *
 * @param props - Component props.
 * @param props.onChange - Callback fired when the value changes
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.className - Optional CSS class name for styling
 * @returns JSX element
 */
export function SsoProviderDeleteModalContent({
  onChange,
  customMessages = {},
  className,
}: SsoProviderDeleteModalContentProps) {
  const handleInputChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    onChange(event.target.value);
  };

  const { t } = useTranslator('idp_management.delete_sso_provider.modal.content', customMessages);

  return (
    <div className={className}>
      <p
        id="delete-modal-content-description"
        className={cn(
          'font-normal block text-sm text-left text-(length:--font-size-paragraph) text-muted-foreground mt-6 mb-6',
        )}
      >
        {t('description')}
      </p>
      <Label
        htmlFor="provider-name"
        className="text-sm text-(length:--font-size-label) font-medium"
      >
        {t('field.label')}
      </Label>
      <TextField
        id="provider-name"
        type="text"
        placeholder={t('field.placeholder')}
        onChange={handleInputChange}
        className="mt-2 mb-6"
      />
    </div>
  );
}

/**
 * SSO provider deletion modal.
 * @module provider-delete-modal
 * @internal
 */

import * as React from 'react';

import { SsoProviderDeleteModalContent } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-delete/provider-delete-modal-content';
import { Modal } from '@/components/ui/modal';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { SsoProviderDeleteModalProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-delete-types';

/**
 *
 * @param props - Component props.
 * @param props.className - Optional CSS class name for styling
 * @param props.isOpen - Whether the modal/dialog is open
 * @param props.onClose - Callback fired when the component should close
 * @param props.provider - SSO provider object
 * @param props.onDelete - Callback fired when delete action is triggered
 * @param props.isLoading - Whether the component is in a loading state
 * @param props.customMessages - Custom translation messages to override defaults
 * @returns JSX element
 */
export function SsoProviderDeleteModal({
  className,
  isOpen,
  onClose,
  provider,
  onDelete,
  isLoading = false,
  customMessages = {},
}: SsoProviderDeleteModalProps) {
  const { t } = useTranslator('idp_management.delete_sso_provider', customMessages);
  const [confirmationText, setConfirmationText] = React.useState('');

  const handleModalContentChange = React.useCallback((value: string) => {
    setConfirmationText(value);
  }, []);

  const handleDelete = React.useCallback(async () => {
    if (provider) {
      await onDelete(provider);
      onClose();
    }
  }, [onDelete, provider, onClose]);

  const handleOpenChange = React.useCallback(
    (open: boolean) => {
      if (!open) {
        onClose();
      }
    },
    [onClose],
  );

  React.useEffect(() => {
    if (isOpen) {
      setConfirmationText('');
    }
  }, [isOpen]);

  return (
    <Modal
      open={isOpen}
      onOpenChange={handleOpenChange}
      className={cn('p-10', className)}
      title={t('modal.title', { providerName: provider.name })}
      content={
        <div className="space-y-6">
          <p className={cn('text-sm text-muted-foreground text-(length:--font-size-paragraph)')}>
            {t('modal.description', { providerName: provider.name })}
          </p>

          <SsoProviderDeleteModalContent
            onChange={handleModalContentChange}
            customMessages={customMessages.modal?.content}
          />
        </div>
      }
      modalActions={{
        isLoading,
        nextAction: {
          type: 'button',
          label: t('modal.actions.delete_button_label'),
          onClick: handleDelete,
          variant: 'destructive',
          disabled: isLoading || confirmationText !== provider.name,
        },
        previousAction: {
          label: t('modal.actions.cancel_button_label'),
          onClick: onClose,
        },
      }}
    />
  );
}

/**
 * SSO provider remove from organization modal.
 * @module provider-remove-modal
 * @internal
 */

import * as React from 'react';

import { SsoProviderDeleteModalContent } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-delete/provider-delete-modal-content';
import { Modal } from '@/components/ui/modal';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { SsoProviderRemoveFromOrganizationModalProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-delete-types';

/**
 *
 * @param props - Component props.
 * @param props.className - Optional CSS class name for styling
 * @param props.isOpen - Whether the modal/dialog is open
 * @param props.onClose - Callback fired when the component should close
 * @param props.provider - SSO provider object
 * @param props.organizationName - Name of the organization
 * @param props.onRemove - Callback fired when remove action is triggered
 * @param props.isLoading - Whether the component is in a loading state
 * @param props.customMessages - Custom translation messages to override defaults
 * @returns JSX element
 */
export function SsoProviderRemoveFromOrganizationModal({
  className,
  isOpen,
  onClose,
  provider,
  organizationName,
  onRemove,
  isLoading = false,
  customMessages = {},
}: SsoProviderRemoveFromOrganizationModalProps) {
  const { t } = useTranslator('idp_management.remove_sso_provider', customMessages);
  const [confirmationText, setConfirmationText] = React.useState('');

  const handleModalContentChange = React.useCallback((value: string) => {
    setConfirmationText(value);
  }, []);

  const handleRemove = React.useCallback(async () => {
    if (provider) {
      await onRemove(provider);
      onClose();
    }
  }, [onRemove, provider, onClose]);

  const handleOpenChange = React.useCallback(
    (open: boolean) => {
      if (!open) {
        onClose();
      }
    },
    [onClose],
  );

  React.useEffect(() => {
    if (isOpen) {
      setConfirmationText('');
    }
  }, [isOpen]);

  return (
    <Modal
      open={isOpen}
      onOpenChange={handleOpenChange}
      className={cn('p-10', className)}
      title={t('modal.title', {
        providerName: provider.name,
        organizationName: organizationName,
      })}
      content={
        <div className="space-y-6">
          <p className={cn('text-sm text-muted-foreground text-(length:--font-size-paragraph)')}>
            <>
              {t.trans('modal.description', {
                components: {
                  bold: (children: string) => <strong key="provider-name">{children}</strong>,
                },
                vars: { providerName: provider.name },
              })}
            </>
          </p>

          <SsoProviderDeleteModalContent
            onChange={handleModalContentChange}
            customMessages={customMessages.modal?.content}
          />
        </div>
      }
      modalActions={{
        isLoading,
        nextAction: {
          type: 'button',
          label: t('modal.actions.remove_button_text'),
          onClick: handleRemove,
          variant: 'destructive',
          disabled: isLoading || confirmationText !== provider.name,
        },
        previousAction: {
          label: t('modal.actions.cancel_button_text'),
          onClick: onClose,
        },
      }}
    />
  );
}

/**
 * SSO provider table row actions column.
 * @module sso-provider-table-action
 * @internal
 */

import { MoreHorizontal, Edit, Trash2 } from 'lucide-react';
import * as React from 'react';

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuPortal,
} from '@/components/ui/dropdown-menu';
import { Spinner } from '@/components/ui/spinner';
import { Switch } from '@/components/ui/switch';
import { Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import { useTranslator } from '@/hooks/shared/use-translator';
import type { SsoProviderTableActionsColumnProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-table-types';

/**
 * SsoProviderTableActionsColumn Component
 * Handles the actions column for SSO Provider table with enable/disable toggle and dropdown menu
 * @param props - Component props.
 * @param props.provider - SSO provider object
 * @param props.shouldAllowDeletion - Whether deletion should be allowed
 * @param props.readOnly - Whether the component is in read-only mode
 * @param props.isUpdating - Whether an update operation is in progress
 * @param props.isUpdatingId - ID of the item currently being updated
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.edit - Edit mode configuration
 * @param props.onToggleEnabled - Callback fired when enabled state is toggled
 * @param props.onEdit - Callback fired when edit action is triggered
 * @param props.onDelete - Callback fired when delete action is triggered
 * @param props.onRemoveFromOrganization - Callback fired when removing from organization
 * @returns JSX element
 */
export function SsoProviderTableActionsColumn({
  provider,
  shouldAllowDeletion,
  readOnly = false,
  isUpdating = false,
  isUpdatingId,
  customMessages = {},
  edit,
  onToggleEnabled,
  onEdit,
  onDelete,
  onRemoveFromOrganization,
}: SsoProviderTableActionsColumnProps) {
  const { t } = useTranslator('idp_management.sso_provider_table', customMessages);

  const handleToggleEnabled = React.useCallback(
    (checked: boolean) => {
      onToggleEnabled(provider, checked);
    },
    [provider, onToggleEnabled],
  );

  const handleEdit = React.useCallback(() => {
    onEdit(provider);
  }, [provider, onEdit]);

  const handleDelete = React.useCallback(() => {
    onDelete(provider);
  }, [provider, onDelete]);

  const handleRemoveFromOrganization = React.useCallback(() => {
    onRemoveFromOrganization(provider);
  }, [provider, onRemoveFromOrganization]);

  return (
    <div className="flex items-center justify-end gap-4 min-w-0">
      {isUpdating && isUpdatingId === provider.id ? (
        <Spinner size="sm" className="m-auto" />
      ) : (
        <Tooltip>
          <TooltipTrigger asChild>
            <span>
              <Switch
                checked={provider.is_enabled ?? false}
                onCheckedChange={handleToggleEnabled}
                disabled={readOnly || isUpdating}
              />
            </span>
          </TooltipTrigger>
          <TooltipContent>
            {provider.is_enabled
              ? t('table.actions.enabled_tooltip')
              : t('table.actions.disabled_tooltip')}
          </TooltipContent>
        </Tooltip>
      )}

      <DropdownMenu>
        <DropdownMenuTrigger className="h-8 w-8 p-0 rounded-xl bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 shadow-sm transition-all duration-200 hover:bg-gray-50 dark:hover:bg-gray-800 hover:shadow-md focus:outline-none focus:ring-2 focus:ring-blue-500">
          <MoreHorizontal className="h-4 w-4 text-gray-600 dark:text-gray-400" />
        </DropdownMenuTrigger>
        <DropdownMenuPortal>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={handleEdit} disabled={readOnly || !edit || edit.disabled}>
              <Edit className="mr-2 h-4 w-4" />
              {t('table.actions.edit_button_text')}
            </DropdownMenuItem>
            {shouldAllowDeletion && (
              <DropdownMenuItem
                onClick={handleDelete}
                className="text-destructive-foreground focus:text-destructive-foreground"
                disabled={readOnly}
              >
                <Trash2 className="mr-2 h-4 w-4" />
                {t('table.actions.delete_button_text')}
              </DropdownMenuItem>
            )}
            <DropdownMenuItem
              onClick={handleRemoveFromOrganization}
              className="text-destructive-foreground focus:text-destructive-foreground"
              disabled={readOnly}
            >
              <Trash2 className="mr-2 h-4 w-4" />
              {t('table.actions.remove_button_text')}
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenuPortal>
      </DropdownMenu>
    </div>
  );
}

/**
 * Data table with sorting and actions.
 * @module data-table
 * @internal
 */

import type { ActionButton as CoreActionButton } from '@auth0/universal-components-core';
import {
  useReactTable,
  getCoreRowModel,
  getSortedRowModel,
  flexRender,
} from '@tanstack/react-table';
import type { SortingState, ColumnDef } from '@tanstack/react-table';
import { Copy } from 'lucide-react';
import React, { useState, useMemo } from 'react';

import { MiddleEllipsisText } from '@/components/auth0/shared/middle-ellipsis-text';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { InlineCode } from '@/components/ui/inline-code';
import { Spinner } from '@/components/ui/spinner';
import { Switch } from '@/components/ui/switch';
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from '@/components/ui/table';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip';
import { cn } from '@/lib/utils';

interface ActionButton extends Omit<CoreActionButton, 'onClick'> {
  onClick: (event: React.MouseEvent<HTMLButtonElement>) => void;
}

type AlignmentType = 'left' | 'center' | 'right';

export interface BaseColumn<Item> {
  title: string;
  accessorKey: keyof Item;
  width?: string;
  enableSorting?: boolean;
  headerAlign?: AlignmentType;
}

export interface TextColumn<Item> extends BaseColumn<Item> {
  type: 'text';
  render?: (item: Item, value: unknown) => React.ReactNode;
}

export interface DateColumn<Item> extends BaseColumn<Item> {
  type: 'date';
  format?: 'short' | 'medium' | 'long' | 'relative';
  render?: (item: Item, value: Date | string | number) => React.ReactNode;
}

export interface SwitchColumn<Item> extends BaseColumn<Item> {
  type: 'switch';
  onToggle?: (checked: boolean, item: Item) => void;
}

export interface ButtonColumn<Item> extends BaseColumn<Item> {
  type: 'button';
  buttonText: string;
  variant?: 'primary' | 'destructive' | 'outline' | 'ghost' | 'link';
  onClick: (item: Item) => void;
}

export interface CopyColumnLabels {
  copyTooltip?: string;
  copiedTooltip?: string;
}

export interface CopyColumn<Item> extends BaseColumn<Item> {
  type: 'copy';
}

export interface BadgeColumn<Item> extends BaseColumn<Item> {
  type: 'badge';
  variant?: 'default' | 'secondary' | 'destructive' | 'outline' | 'success';
}

export interface ActionsColumn<Item> extends Omit<BaseColumn<Item>, 'accessorKey'> {
  type: 'actions';
  accessorKey?: keyof Item;
  render: (item: Item) => React.ReactNode;
}

export interface CustomColumn<Item> extends BaseColumn<Item> {
  type: 'custom';
  render: (item: Item, value: unknown) => React.ReactNode;
}

export type Column<Item> =
  | TextColumn<Item>
  | DateColumn<Item>
  | SwitchColumn<Item>
  | ButtonColumn<Item>
  | CopyColumn<Item>
  | BadgeColumn<Item>
  | ActionsColumn<Item>
  | CustomColumn<Item>;

export interface EmptyStateProps {
  title: string;
  subtitle?: string;
  action?: ActionButton;
}

export interface DataTableProps<Item> {
  data: Item[];
  columns: Column<Item>[];
  loading?: boolean;
  loader?: React.ReactNode;
  emptyState?: EmptyStateProps;
  onRowClick?: (rowData: Item) => void;
  className?: string;
  headerAlign?: AlignmentType;
}

const ALIGNMENT_CLASSES = {
  text: {
    left: 'text-left',
    center: 'text-center',
    right: 'text-right',
  },
  flex: {
    left: 'justify-start',
    center: 'justify-center',
    right: 'justify-end',
  },
} as const;

const isEmpty = (value: unknown): boolean => {
  return value === null || value === undefined || value === '';
};

const formatDate = (value: Date | string | number, format: string = 'medium'): string => {
  const date = new Date(value);
  if (isNaN(date.getTime())) return 'Invalid Date';

  switch (format) {
    case 'short':
      return date.toLocaleDateString();
    case 'long':
      return date.toLocaleDateString(undefined, {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      });
    case 'relative': {
      const now = new Date();
      const diffTime = date.getTime() - now.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (Math.abs(diffDays) === 0) return 'Today';
      if (diffDays === 1) return 'Tomorrow';
      if (diffDays === -1) return 'Yesterday';
      if (diffDays > 0) return `In ${diffDays} days`;
      return `${Math.abs(diffDays)} days ago`;
    }
    case 'medium':
    default:
      return date.toLocaleDateString(undefined, {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      });
  }
};

const DEFAULT_COPY_LABELS: Required<CopyColumnLabels> = {
  copyTooltip: 'Copy to clipboard',
  copiedTooltip: 'Copied!',
};

/**
 * Copy button with clipboard functionality.
 * @param props - Component props.
 * @param props.value - Value to copy
 * @param props.labels - Tooltip labels
 * @returns JSX element
 */
function CopyButton({
  value,
  labels = DEFAULT_COPY_LABELS,
}: {
  value: unknown;
  labels?: CopyColumnLabels;
}) {
  const [copied, setCopied] = useState(false);
  const [copyTooltipOpen, setCopyTooltipOpen] = useState(false);
  const stringValue = String(value);

  const handleCopy = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!value) return;

    try {
      await navigator.clipboard.writeText(stringValue);
      setCopied(true);
      setCopyTooltipOpen(true);

      setTimeout(() => {
        setCopied(false);
        setCopyTooltipOpen(false);
      }, 2000);
    } catch (error) {
      console.error('Failed to copy text:', error);
    }
  };

  return (
    <InlineCode className="w-full flex items-center justify-between gap-2 pr-1">
      <span className="min-w-0 flex-1">
        <MiddleEllipsisText text={stringValue} className="text-muted-foreground" />
      </span>
      <Tooltip open={copyTooltipOpen} onOpenChange={setCopyTooltipOpen}>
        <TooltipTrigger asChild>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleCopy}
            className="h-6 w-6 p-0 hover:bg-muted/50 shrink-0"
            aria-label={copied ? labels.copiedTooltip : labels.copyTooltip}
          >
            <Copy className="h-3 w-3" />
          </Button>
        </TooltipTrigger>
        <TooltipContent>
          <p>{copied ? labels.copiedTooltip : labels.copyTooltip}</p>
        </TooltipContent>
      </Tooltip>
    </InlineCode>
  );
}

/**
 * Renders a text column cell.
 * @param item - Data item.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderTextColumn<Item>(
  item: Item,
  value: unknown,
  column: TextColumn<Item>,
): React.ReactNode {
  if (column.render) {
    return column.render(item, value);
  }

  return <span className="text-muted-foreground">{String(value)}</span>;
}

/**
 * Renders a date column cell.
 * @param item - Data item.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderDateColumn<Item>(
  item: Item,
  value: Date | string | number,
  column: DateColumn<Item>,
): React.ReactNode {
  if (column.render) {
    return column.render(item, value);
  }
  const formattedDate = formatDate(value, column.format);

  return (
    <span className="text-muted-foreground" title={new Date(value).toISOString()}>
      {formattedDate}
    </span>
  );
}

/**
 * Renders a switch column cell.
 * @param item - Data item.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderSwitchColumn<Item>(
  item: Item,
  value: boolean,
  column: SwitchColumn<Item>,
): React.ReactNode {
  const handleToggle = (checked: boolean) => {
    column.onToggle?.(checked, item);
  };

  return (
    <div onClick={(e) => e.stopPropagation()}>
      <Switch checked={!!value} onCheckedChange={handleToggle} />
    </div>
  );
}

/**
 * Renders a button column cell.
 * @param item - Data item.
 * @param column - Column configuration.
 * @returns React node
 */
function renderButtonColumn<Item>(item: Item, column: ButtonColumn<Item>): React.ReactNode {
  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    column.onClick(item);
  };

  return (
    <Button variant={column.variant} size="sm" onClick={handleClick}>
      {column.buttonText}
    </Button>
  );
}

/**
 * Renders a badge column cell.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderBadgeColumn<Item>(value: unknown, column: BadgeColumn<Item>): React.ReactNode {
  return <Badge variant={column.variant}>{String(value)}</Badge>;
}

/**
 * Renders a copy column cell.
 * @param value - Cell value.
 * @returns React node
 */
function renderCopyColumn(value: unknown): React.ReactNode {
  return <CopyButton value={value} />;
}

/**
 * Empty state component for data table.
 * @param props - Component props.
 * @param props.title - Empty state title.
 * @param props.subtitle - Empty state subtitle.
 * @param props.action - Optional action button config.
 * @returns JSX element
 */
function EmptyState({ title, subtitle, action }: EmptyStateProps) {
  return (
    <div className="text-center py-12">
      <h3 className="text-md font-medium text-foreground mb-2">{title}</h3>
      {subtitle && <p className="text-sm text-muted-foreground mb-4">{subtitle}</p>}
      {action && (
        <Button variant={action.variant} onClick={action.onClick}>
          {action.label}
        </Button>
      )}
    </div>
  );
}

/**
 * Generic data table component.
 * @param props - Component props.
 * @param props.data - Table data items.
 * @param props.columns - Column configurations.
 * @param props.loading - Loading state.
 * @param props.loader - Custom loader component.
 * @param props.emptyState - Empty state configuration.
 * @param props.onRowClick - Row click handler.
 * @param props.className - Additional CSS classes.
 * @param props.headerAlign - Default header alignment.
 * @returns JSX element
 */
export function DataTable<Item>({
  data,
  columns,
  loading = false,
  loader,
  emptyState,
  onRowClick,
  className,
  headerAlign = 'left',
}: DataTableProps<Item>) {
  const [sorting, setSorting] = useState<SortingState>([]);

  const tableColumns = useMemo<ColumnDef<Item>[]>(() => {
    return columns.map((column, index) => {
      return {
        id: `column-${index}`,
        accessorKey: column.accessorKey as string,
        header: column.title,
        size: column.width
          ? isNaN(Number(column.width))
            ? undefined
            : Number(column.width)
          : undefined,
        enableSorting: column.enableSorting !== false && !!column.accessorKey,
        meta: {
          headerAlign: column.headerAlign || headerAlign || 'left',
          column: column,
        },

        cell: ({ getValue, row }) => {
          const value = getValue();
          const item = row.original;

          if (column.type === 'actions') {
            return <div onClick={(e) => e.stopPropagation()}>{column.render(item)}</div>;
          }

          if (column.type === 'custom') {
            return <>{column.render(item, value)}</>;
          }

          if (column.type === 'switch') {
            return renderSwitchColumn(item, value as boolean, column);
          }

          if (column.type === 'button') {
            return renderButtonColumn(item, column);
          }

          if (isEmpty(value)) {
            return null;
          }

          switch (column.type) {
            case 'text':
              return renderTextColumn(item, value, column);
            case 'date':
              return renderDateColumn(item, value as Date | string | number, column);
            case 'copy':
              return renderCopyColumn(value);
            case 'badge':
              return renderBadgeColumn(value, column);
            default:
              return <span className="text-foreground">{String(value)}</span>;
          }
        },
      };
    });
  }, [columns, headerAlign]);

  const table = useReactTable({
    data,
    columns: tableColumns,
    state: {
      sorting,
    },
    onSortingChange: setSorting,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    manualPagination: true,
  });

  if (loading) {
    return (
      <div className={cn('w-full flex items-center justify-center py-8', className)}>
        {loader || <Spinner />}
      </div>
    );
  }

  return (
    <div className={cn('w-full', className)}>
      <Table>
        <TableHeader>
          {table.getHeaderGroups().map((headerGroup) => (
            <TableRow key={headerGroup.id}>
              {headerGroup.headers.map((header) => {
                const canSort = header.column.getCanSort();
                const sortDirection = header.column.getIsSorted();
                const meta = header.column.columnDef.meta as {
                  headerAlign: AlignmentType;
                  column: Column<Item>;
                };

                return (
                  <TableHead
                    key={header.id}
                    className={cn(
                      canSort && 'hover:bg-muted/50',
                      'transition-colors',
                      ALIGNMENT_CLASSES.text[meta.headerAlign],
                    )}
                    style={{
                      width: meta.column.width,
                      minWidth: meta.column.width,
                      maxWidth: meta.column.width,
                    }}
                    onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
                    isSortable={canSort}
                    sortDirection={sortDirection}
                  >
                    {flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                );
              })}
            </TableRow>
          ))}
        </TableHeader>
        <TableBody>
          {table.getRowModel().rows.length === 0 ? (
            <TableRow disableHover>
              <TableCell colSpan={columns.length}>
                <EmptyState
                  {...(emptyState ?? {
                    title: 'No data available',
                    subtitle: 'There are no items to display.',
                  })}
                />
              </TableCell>
            </TableRow>
          ) : (
            table.getRowModel().rows.map((row) => (
              <TableRow
                key={row.id}
                className={cn(
                  onRowClick && 'cursor-pointer hover:bg-muted/50',
                  'transition-colors',
                )}
                onClick={() => onRowClick?.(row.original)}
              >
                {row.getVisibleCells().map((cell) => {
                  const meta = cell.column.columnDef.meta as {
                    column: Column<Item>;
                  };
                  return (
                    <TableCell
                      key={cell.id}
                      className="text-left"
                      style={{
                        width: meta.column.width,
                        minWidth: meta.column.width,
                        maxWidth: meta.column.width,
                      }}
                    >
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  );
                })}
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>
    </div>
  );
}

/**
 * Form action buttons component.
 * @module form-actions
 * @internal
 */

import type { ActionButton } from '@auth0/universal-components-core';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { Spinner } from '@/components/ui/spinner';
import { cn } from '@/lib/utils';

export interface FormActionsProps<T = void> {
  hasUnsavedChanges?: boolean;
  isLoading?: boolean;
  nextAction?: Partial<ActionButton<T>>;
  previousAction?: Partial<ActionButton<T>>;
  showPrevious?: boolean;
  showNext?: boolean;
  showUnsavedChanges?: boolean;
  align?: 'left' | 'right';
  className?: string;
  unsavedChangesText?: string;
}

const DEFAULT_NEXT_ACTION: ActionButton = {
  type: 'submit',
  label: 'Save',
  variant: 'primary',
  onClick: () => {},
};

const DEFAULT_PREVIOUS_ACTION: ActionButton = {
  label: 'Cancel',
  variant: 'outline',
  onClick: () => {},
};

export const FormActions: React.FC<FormActionsProps> = ({
  hasUnsavedChanges = false,
  isLoading = false,
  nextAction,
  previousAction,
  className,
  showPrevious = true,
  showNext = true,
  showUnsavedChanges = true,
  align = 'right',
  unsavedChangesText = 'Unsaved changes',
}) => {
  const nextButtonProps = React.useMemo(
    () => ({ ...DEFAULT_NEXT_ACTION, ...nextAction }),
    [nextAction],
  );

  const previousButtonProps = React.useMemo(
    () => ({ ...DEFAULT_PREVIOUS_ACTION, ...previousAction }),
    [previousAction],
  );

  const handleNextClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      nextButtonProps.onClick(e.nativeEvent);
    },
    [nextButtonProps.onClick],
  );

  const handlePreviousClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      previousButtonProps.onClick(e.nativeEvent);
    },
    [previousButtonProps.onClick],
  );

  const showUnsavedIndicator = showUnsavedChanges && hasUnsavedChanges;
  const isPreviousVisible = showUnsavedChanges ? showPrevious && hasUnsavedChanges : showPrevious;

  return (
    <div
      className={cn(
        'flex flex-row items-center gap-2 p-2',
        align === 'right' ? 'justify-end' : 'justify-start',
        className,
      )}
    >
      {showUnsavedIndicator && (
        <span className="text-sm text-muted-foreground">{unsavedChangesText}</span>
      )}

      {showPrevious && (
        <Button
          type="button"
          variant={previousButtonProps.variant}
          size={previousButtonProps.size}
          onClick={handlePreviousClick}
          disabled={
            previousButtonProps.disabled || isLoading || (showUnsavedChanges && !hasUnsavedChanges)
          }
          className={cn(
            'FormActions-previous',
            showUnsavedChanges && !isPreviousVisible && 'invisible',
          )}
          aria-hidden={showUnsavedChanges && !isPreviousVisible}
          tabIndex={isPreviousVisible ? 0 : -1}
        >
          {previousButtonProps.label}
        </Button>
      )}

      {showNext && (
        <Button
          type={nextButtonProps.type}
          variant={nextButtonProps.variant}
          size={nextButtonProps.size}
          disabled={nextButtonProps.disabled || isLoading}
          className="FormActions-next min-w-17.5"
          {...(nextButtonProps.type !== 'submit' && { onClick: handleNextClick })}
        >
          {isLoading ? (
            <Spinner
              colorScheme={nextButtonProps.variant === 'destructive' ? 'primary' : 'foreground'}
              size="sm"
              aria-hidden="true"
            />
          ) : (
            <>
              {nextButtonProps.icon && (
                <span className="mr-2" aria-hidden="true">
                  {nextButtonProps.icon as React.ReactNode}
                </span>
              )}
              {nextButtonProps.label}
            </>
          )}
        </Button>
      )}
    </div>
  );
};

