/**
 * Toast settings management hook.
 * @module use-toast-provider
 * @internal
 */

import { useEffect, useMemo } from 'react';

import { setGlobalToastSettings } from '@/components/auth0/shared/toast';
import { DEFAULT_TOAST_SETTINGS, type ToastSettings } from '@/types/toast-types';

/**
 * Hook to merge and apply toast settings.
 * @param toastSettings - Optional toast settings.
 * @returns Merged toast settings.
 * @internal
 */
export const useToastProvider = (toastSettings?: ToastSettings) => {
  const mergedToastSettings = useMemo(() => {
    if (!toastSettings) {
      return DEFAULT_TOAST_SETTINGS;
    }

    if (toastSettings.provider === 'custom') {
      return toastSettings;
    }

    const defaultSonnerSettings =
      DEFAULT_TOAST_SETTINGS.provider === 'sonner' ? DEFAULT_TOAST_SETTINGS.settings || {} : {};

    return {
      provider: 'sonner' as const,
      settings: {
        ...defaultSonnerSettings,
        ...(toastSettings.provider === 'sonner' ? toastSettings.settings : {}),
      },
    } satisfies ToastSettings;
  }, [toastSettings]);

  useEffect(() => {
    setGlobalToastSettings(mergedToastSettings);
  }, [mergedToastSettings]);

  return mergedToastSettings;
};

/**
 * i18n translator hook.
 * @module use-translator
 */

import { type EnhancedTranslationFunction } from '@auth0/universal-components-core';
import { useMemo, useCallback } from 'react';

import { useCoreClient } from '@/hooks/shared/use-core-client';

/**
 * Hook to access i18n translations.
 * @param namespace - Translation namespace.
 * @param overrides - Optional translation overrides.
 * @returns Translator function and language utilities.
 */
export function useTranslator(
  namespace: string,
  overrides?: Record<string, unknown>,
): {
  t: EnhancedTranslationFunction;
  changeLanguage: (language: string, fallbackLanguage?: string) => Promise<void>;
  currentLanguage: string;
  fallbackLanguage: string | undefined;
} {
  const { coreClient } = useCoreClient();

  if (!coreClient) {
    throw new Error(
      'useTranslator must be used within Auth0ComponentProvider with initialized CoreClient',
    );
  }

  const translator = useMemo(() => {
    return coreClient.i18nService.translator(namespace, overrides);
  }, [coreClient, namespace, overrides]);

  const changeLanguage = useCallback(
    async (language: string, fallbackLanguage?: string) => {
      await coreClient.i18nService.changeLanguage(language, fallbackLanguage);
    },
    [coreClient],
  );

  return {
    t: translator,
    changeLanguage,
    currentLanguage: coreClient.i18nService.currentLanguage,
    fallbackLanguage: coreClient.i18nService.fallbackLanguage,
  };
}

